  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskAction = useAction(createTask)
  const updateTaskAction = useAction(updateTask)

  const handleCreateTask = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    const form = e.currentTarget
    const description = (form.elements.namedItem('description') as HTMLInputElement).value
    try {
      await createTaskAction({ description })
      form.reset()
    } catch (err: any) {
      alert('Error creating task: ' + err.message)
    }
  }

  const handleToggleTask = async (id: number, isDone: boolean) => {
    try {
      await updateTaskAction({ id, isDone: !isDone })
    } catch (err: any) {
      alert('Error updating task: ' + err.message)
    }
  }

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error.message

  return (
    <div style={{ padding: '20px' }}>
      <h1>My Todo List</h1>
      <button onClick={logout}>Logout</button>
      <div style={{ marginTop: '20px' }}>
        <form onSubmit={handleCreateTask}>
          <input name="description" placeholder="Task description" required />
          <button type="submit">Add Task</button>
        </form>
      </div>
      <ul style={{ listStyle: 'none', padding: 0, marginTop: '20px' }}>
        {(tasks as any[])?.map((task: any) => (
          <li key={task.id} style={{ marginBottom: '10px' }}>
            <label>
              <input
                type="checkbox"
                checked={task.isDone}
                onChange={() => handleToggleTask(task.id, task.isDone)}
              />
              <span style={{ marginLeft: '10px', textDecoration: task.isDone ? 'line-through' : 'none' }}>
                {task.description}
              </span>
            </label>
          </li>
        ))}
      </ul>
    </div>
  )
}

